import{_ as a,o as l,c as o,a2 as i}from"./chunks/framework.VshInwhI.js";const h=JSON.parse('{"title":"前端 Monorepo 架构规范","description":"","frontmatter":{},"headers":[],"relativePath":"mango-pmo/rules/frontend/06-monorepo-architecture.md","filePath":"mango-pmo/rules/frontend/06-monorepo-architecture.md"}'),c={name:"mango-pmo/rules/frontend/06-monorepo-architecture.md"};function d(r,e,n,t,p,s){return l(),o("div",null,[...e[0]||(e[0]=[i('<h1 id="前端-monorepo-架构规范" tabindex="-1">前端 Monorepo 架构规范 <a class="header-anchor" href="#前端-monorepo-架构规范" aria-label="Permalink to &quot;前端 Monorepo 架构规范&quot;">​</a></h1><h2 id="_1-分层" tabindex="-1">1. 分层 <a class="header-anchor" href="#_1-分层" aria-label="Permalink to &quot;1. 分层&quot;">​</a></h2><ul><li><code>apps/*</code>：应用基座和部署单元。</li><li><code>packages/common</code>：公共能力。</li><li><code>packages/api-schema</code>：共享契约。</li><li><code>packages/*</code> 业务包：按领域拆分业务能力。</li></ul><h2 id="_2-依赖规则" tabindex="-1">2. 依赖规则 <a class="header-anchor" href="#_2-依赖规则" aria-label="Permalink to &quot;2. 依赖规则&quot;">​</a></h2><ul><li><code>apps</code> 可以依赖 <code>packages/*</code>。</li><li>业务包可以依赖 <code>common</code> 和 <code>api-schema</code>。</li><li>公共包禁止依赖 <code>apps</code>。</li><li>业务包之间禁止随意互相依赖。</li><li>禁止循环依赖。</li></ul><h2 id="_3-宿主职责" tabindex="-1">3. 宿主职责 <a class="header-anchor" href="#_3-宿主职责" aria-label="Permalink to &quot;3. 宿主职责&quot;">​</a></h2><ul><li>宿主只负责布局、路由聚合、权限拦截、全局初始化。</li><li>宿主不承载公共组件第二实现。</li><li>宿主不长期保留业务包已下沉的代码。</li><li>宿主可以提供单体模式样式聚合入口，但不能作为业务 package 样式的唯一来源。</li><li>宿主或 shell 不负责把业务 package 样式注入到微前端隔离容器。</li></ul><h2 id="_4-公共能力规则" tabindex="-1">4. 公共能力规则 <a class="header-anchor" href="#_4-公共能力规则" aria-label="Permalink to &quot;4. 公共能力规则&quot;">​</a></h2><ul><li>可复用组件进入对应 <code>packages/*</code>。</li><li>公共组件需要统一导出。</li><li>公共组件禁止直接依赖宿主 store、router、api、i18n。</li><li>公共组件依赖的 API 必须放在对应公共位置。</li><li>可复用页面、组件和能力的样式必须跟随所属 package，package 通过 <code>./style.css</code> 公开样式入口。</li><li>单体聚合入口只能 <code>@import</code> 各 package 样式，禁止复制或重写 package 私有样式。</li><li>admin 类宿主或业务管理应用集成 package 必须通过本应用的 package manifest 一处显式声明，样式聚合文件由通用脚本生成，禁止手工长期维护 package 样式清单。</li><li>新增或移除 admin 类 package 后必须运行样式生成校验，确保声明、消费方依赖和 package <code>./style.css</code> 导出一致。</li><li>admin 类宿主或业务管理应用的 <code>dev</code> 和 <code>build</code> 必须自动生成样式聚合文件，避免依赖人工预先执行生成命令。</li><li>package 样式生成工具必须基于消费方 <code>package.json</code> 的 Node 依赖解析，不得只依赖当前 monorepo 目录结构；同一机制必须支持 workspace package 和已发布 npm/Nexus package。</li><li>官方业务模块出现在 <code>@mango/admin/full</code>、<code>mango-cli</code> full/custom 模块清单或管理端页面注册链时，必须同步出现在样式聚合链或微前端自身入口，并通过 <code>pnpm admin:module-styles:check</code>。</li><li>微前端 app 必须按运行模块显式引入自身依赖的 package 样式，例如 workflow app 引入 workflow package 样式。</li><li>业务项目消费 Mango package 时应通过 package 公开入口引入样式，不能依赖 <code>apps/*</code> 或仓库源码路径。</li><li>开发中心和组件示例属于展示与验证承载层，只能依赖被展示组件的公开包入口和样式入口。</li><li>开发中心不得作为组件样式总包；业务项目不得为了使用某个组件而被迫依赖开发中心 package。</li><li>通用组件样式归属 <code>@mango/common/style.css</code>，文件组件样式归属 <code>@mango/file/style.css</code>，工作流组件样式归属 <code>@mango/workflow/style.css</code>；示例中心只引入这些入口，不接管运行样式。</li></ul><h2 id="_5-路由规则" tabindex="-1">5. 路由规则 <a class="header-anchor" href="#_5-路由规则" aria-label="Permalink to &quot;5. 路由规则&quot;">​</a></h2><ul><li>路由按模块组织。</li><li>动态路由集中处理。</li><li>跨包页面必须显式注册或有统一映射。</li></ul><h2 id="_6-mock-与真实接口" tabindex="-1">6. Mock 与真实接口 <a class="header-anchor" href="#_6-mock-与真实接口" aria-label="Permalink to &quot;6. Mock 与真实接口&quot;">​</a></h2><ul><li>Mock 和真实接口保持同一契约。</li><li>不允许开发态和构建态走两套不一致协议。</li></ul><h2 id="_7-迁移规则" tabindex="-1">7. 迁移规则 <a class="header-anchor" href="#_7-迁移规则" aria-label="Permalink to &quot;7. 迁移规则&quot;">​</a></h2><ul><li>下沉代码时同时迁移类型、样式、测试、导出。</li><li>迁移完成后删除原重复实现。</li><li>不保留“先复制，后面再删”的长期重复代码。</li></ul><h2 id="_8-交付要求" tabindex="-1">8. 交付要求 <a class="header-anchor" href="#_8-交付要求" aria-label="Permalink to &quot;8. 交付要求&quot;">​</a></h2><ul><li><code>pnpm build</code> 通过</li><li><code>pnpm dev</code> 可启动</li><li>关键页面可访问</li><li>关键测试可执行</li><li>单体和微前端模式的关键页面样式必须分别验证。</li><li>涉及微前端样式时，E2E 必须保留截图，并验证子应用隔离容器内关键元素 computed style 符合预期。</li><li>涉及 <code>@mango/admin/full</code>、CLI 模块清单、admin 样式聚合或官方业务模块样式的 PR，必须执行 <code>pnpm admin:styles:check</code> 和 <code>pnpm admin:module-styles:check</code>。</li></ul><h2 id="_9-禁止事项" tabindex="-1">9. 禁止事项 <a class="header-anchor" href="#_9-禁止事项" aria-label="Permalink to &quot;9. 禁止事项&quot;">​</a></h2><ul><li><code>packages/*</code> 反向依赖 <code>apps/*</code></li><li>同一能力在宿主和公共包各维护一份</li><li>公共包直接引用宿主别名路径</li><li>业务 package 样式只存在于单体聚合入口</li><li>手工修改单体 admin 生成的 package 样式聚合文件</li><li>微前端页面依赖宿主聚合样式穿透隔离容器</li><li>组件运行样式依赖开发中心、示例中心或文档示例页</li><li>通用组件或业务组件为了显示正常要求额外安装开发中心 package</li></ul>',19)])])}const u=a(c,[["render",d]]);export{h as __pageData,u as default};
